+  auto CanFold = [Cond, &DL, GEPLHS](GEPNoWrapFlags NW) {
+    if (ICmpInst::isEquality(Cond)) {
+      // For equality comparisons, we can only fold if there's no possibility of
+      // pointer wrapping. This happens when either:
+      // 1. The GEP has no-wrap flags, or
+      // 2. The pointer size is large enough that offsets cannot wrap
+      if (NW != GEPNoWrapFlags::none())
+        return true;
+
+      // Check if pointer size is sufficient to prevent wrapping
+      unsigned PtrSizeInBits = DL.getPointerSizeInBits(GEPLHS->getPointerAddressSpace());
+      
+      // Simple conservative check: if pointer size is less than or equal to the 
+      // size of any index type, wrapping could occur
+      for (unsigned i = 1; i < GEPLHS->getNumOperands(); ++i) {
+        unsigned IndexSizeInBits = GEPLHS->getOperand(i)->getType()->getScalarSizeInBits();
+        if (PtrSizeInBits <= IndexSizeInBits) {
+          // Pointer size is not larger than index size, so wrapping is possible
+          return false;
+        }
+      }
+      
+      // Additionally, check if the element size could cause wrapping
+      // For simplicity, if we have a single index and small pointer size, be conservative
+      if (GEPLHS->getNumOperands() == 2) {
+        Type *ElemTy = GEPLHS->getSourceElementType();
+        uint64_t ElemSize = DL.getTypeAllocSize(ElemTy).getFixedValue();
+        // If element size > 1 and pointer size is small, wrapping is likely
+        if (ElemSize > 1 && PtrSizeInBits <= 16) {
+          // Be very conservative for small pointer sizes
+          return false;
+        }
+      }
+      
+      // If we passed all checks, assume no wrapping
+      return true;
+    }
+
+    // Unsigned predicates can be folded if the GEPs have *any* nowrap flags.
+    assert(ICmpInst::isUnsigned(Cond));
+    return NW != GEPNoWrapFlags::none();
+  };
+  auto CanFold = [Cond](GEPNoWrapFlags NW) {
+    if (ICmpInst::isEquality(Cond)) {
+      // For equality comparisons, we can only safely fold if the GEP has no-wrap
+      // flags that guarantee no pointer wrapping can occur.
+      // Without no-wrap flags, pointer arithmetic may wrap (especially with
+      // small pointer sizes like 8-bit pointers), making different indices
+      // produce the same pointer value.
+      return NW != GEPNoWrapFlags::none();
+    }
+
+    // Unsigned predicates can be folded if the GEPs have *any* nowrap flags.
+    assert(ICmpInst::isUnsigned(Cond));
+    return NW != GEPNoWrapFlags::none();
+  };
